<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if (session_status() === PHP_SESSION_NONE) session_start();

function mlv_h($v){return htmlspecialchars((string)$v, ENT_QUOTES, 'UTF-8');}
function mlv_date($v){return (!$v || $v==='0000-00-00') ? '-' : date('d M Y', strtotime($v));}
function mlv_num($v,$d=0){return number_format((float)$v,$d,'.',',');}
function mlv_valid_date($v,$fallback){return preg_match('/^\d{4}-\d{2}-\d{2}$/',(string)$v)?$v:$fallback;}
function mlv_status_class($s){$m=array('DRAFT'=>'warning','SUBMITTED'=>'info','MANAGER_APPROVED'=>'primary','HR_APPROVED'=>'primary','APPROVED'=>'success','REJECTED'=>'danger','RETURNED'=>'warning','CANCELLED'=>'default');return isset($m[$s])?$m[$s]:'default';}
function mlv_type_class($s){$m=array('ANNUAL_LEAVE'=>'success','SICK_LEAVE'=>'warning','SPECIAL_LEAVE'=>'info','MATERNITY_LEAVE'=>'primary','PATERNITY_LEAVE'=>'primary','MARRIAGE_LEAVE'=>'info','BEREAVEMENT_LEAVE'=>'default','UNPAID_LEAVE'=>'danger','PERMISSION'=>'warning','OTHER'=>'default');return isset($m[$s])?$m[$s]:'default';}

$today = date('Y-m-d');
$from = mlv_valid_date(isset($_GET['tgl_awal']) ? $_GET['tgl_awal'] : '', date('Y-01-01'));
$to = mlv_valid_date(isset($_GET['tgl_akhir']) ? $_GET['tgl_akhir'] : '', $today);
$filterType = isset($_GET['leave_type']) ? trim($_GET['leave_type']) : '';
$filterStatus = isset($_GET['status']) ? trim($_GET['status']) : '';
$employee = null; $rows = array(); $approvalMap = array();
$summary = array('total'=>0,'pending'=>0,'approved'=>0,'exception'=>0,'requested_days'=>0,'approved_days'=>0,'quota_used'=>0);
$typeChart = array(); $statusChart = array();

$uid = isset($_SESSION['id_user']) ? (int)$_SESSION['id_user'] : 0;
if ($uid > 0) {
  $employee = $db->fetch("SELECT e.*, u.username, u.foto_user, d.nm_dept, jt.job_title_code, jt.job_title_name, m.employee_no manager_no, m.full_name manager_name
    FROM erp_employee_master e
    LEFT JOIN sys_users u ON u.id=e.user_id
    LEFT JOIN dept d ON d.kd_dept=e.department_code
    LEFT JOIN erp_job_title jt ON jt.id=e.job_title_id
    LEFT JOIN erp_employee_master m ON m.id=e.manager_employee_id
    WHERE e.user_id=? LIMIT 1", array($uid));
}
if ($employee) {
  $where = " WHERE l.employee_id=? AND l.start_date<=? AND l.end_date>=? ";
  $params = array((int)$employee->id, $to, $from);
  if ($filterType !== '') {$where .= " AND l.leave_type=? "; $params[] = $filterType;}
  if ($filterStatus !== '') {$where .= " AND l.workflow_status=? "; $params[] = $filterStatus;}
  $s = $db->fetch("SELECT COUNT(*) total,
      SUM(l.workflow_status IN ('SUBMITTED','MANAGER_APPROVED','HR_APPROVED')) pending,
      SUM(l.workflow_status='APPROVED') approved,
      SUM(l.workflow_status IN ('REJECTED','RETURNED','CANCELLED')) exception,
      COALESCE(SUM(l.total_days),0) requested_days,
      COALESCE(SUM(CASE WHEN l.workflow_status='APPROVED' THEN l.total_days ELSE 0 END),0) approved_days,
      COALESCE(SUM(l.leave_quota_before-l.leave_quota_after),0) quota_used
    FROM erp_leave_request l $where", $params);
  if ($s) foreach ($summary as $k=>$v) $summary[$k] = isset($s->$k) ? (float)$s->$k : 0;
  $stmt = $db->query("SELECT l.*, h.employee_no handover_no, h.full_name handover_name, a.employee_no approver_no, a.full_name approver_name, hr.employee_no hr_no, hr.full_name hr_name
    FROM erp_leave_request l
    LEFT JOIN erp_employee_master h ON h.id=l.handover_to_employee_id
    LEFT JOIN erp_employee_master a ON a.id=l.approver_employee_id
    LEFT JOIN erp_employee_master hr ON hr.id=l.hr_reviewer_employee_id
    $where ORDER BY l.start_date DESC, l.leave_no DESC", $params);
  $rows = $stmt ? $stmt->fetchAll(PDO::FETCH_OBJ) : array();
  $ids = array();
  foreach ($rows as $r) $ids[] = (int)$r->id;
  if ($ids) {
    $in = implode(',', array_fill(0, count($ids), '?'));
    $logs = $db->query("SELECT a.*, e.employee_no, e.full_name FROM erp_leave_approval a LEFT JOIN erp_employee_master e ON e.id=a.approver_employee_id WHERE a.leave_request_id IN ($in) ORDER BY a.leave_request_id,a.id", $ids);
    foreach ($logs as $l) {
      if (!isset($approvalMap[$l->leave_request_id])) $approvalMap[$l->leave_request_id] = array();
      $approvalMap[$l->leave_request_id][] = $l;
    }
  }
  $typeRows = $db->query("SELECT l.leave_type label, COUNT(*) total FROM erp_leave_request l $where GROUP BY l.leave_type ORDER BY total DESC", $params);
  foreach ($typeRows as $r) $typeChart[] = array($r->label, (int)$r->total);
  if (!$typeChart) $typeChart[] = array('No Data',0);
  $statusRows = $db->query("SELECT l.workflow_status label, COUNT(*) total FROM erp_leave_request l $where GROUP BY l.workflow_status ORDER BY total DESC", $params);
  foreach ($statusRows as $r) $statusChart[] = array($r->label, (int)$r->total);
  if (!$statusChart) $statusChart[] = array('No Data',0);
}
$photoUrl = $employee ? erpkb_user_photo_url($employee->foto_user, 'back_profil_foto') : base_admin().'assets/dist/img/default-user-neutral.svg';
$leaveTypes = array('ANNUAL_LEAVE','SICK_LEAVE','SPECIAL_LEAVE','MATERNITY_LEAVE','PATERNITY_LEAVE','MARRIAGE_LEAVE','BEREAVEMENT_LEAVE','UNPAID_LEAVE','PERMISSION','OTHER');
$statuses = array('DRAFT','SUBMITTED','MANAGER_APPROVED','HR_APPROVED','APPROVED','REJECTED','RETURNED','CANCELLED');
?>

