  <div class="row"><div class="col-md-3 col-sm-6"><div class="ml-kpi"><i class="fa fa-calendar"></i><span>Total Request</span><strong><?=mlv_num($summary['total']);?></strong><small><?=mlv_num($summary['requested_days'],2);?> hari diminta</small></div></div><div class="col-md-3 col-sm-6"><div class="ml-kpi"><i class="fa fa-hourglass-half blue"></i><span>Pending Approval</span><strong><?=mlv_num($summary['pending']);?></strong><small>Submitted / Manager / HR review</small></div></div><div class="col-md-3 col-sm-6"><div class="ml-kpi"><i class="fa fa-check orange"></i><span>Approved Days</span><strong><?=mlv_num($summary['approved_days'],2);?></strong><small><?=mlv_num($summary['approved']);?> request approved</small></div></div><div class="col-md-3 col-sm-6"><div class="ml-kpi"><i class="fa fa-minus-circle red"></i><span>Quota Used</span><strong><?=mlv_num($summary['quota_used'],2);?></strong><small>Before-after quota impact</small></div></div></div>

