  <div class="box ml-card"><div class="box-header"><h3 class="box-title"><i class="fa fa-list"></i> Riwayat My Leave</h3></div><div class="box-body table-responsive"><table id="dtb_my_leave" class="table table-bordered table-hover ml-table" style="width:100%"><thead><tr><th>Leave</th><th><?=hr_h('hr_period', 'Period');?></th><th>Days / Quota</th><th>Handover</th><th>Approver</th><th><?=hr_h('common_status', 'Status');?></th><th>Approval History</th><th><?=hr_h('common_action', 'Action');?></th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><strong><?=mlv_h($r->leave_no);?></strong><br><span class="label label-<?=mlv_type_class($r->leave_type);?>"><?=mlv_h($r->leave_type);?></span><br><small><?=mlv_h($r->request_date);?></small></td><td><strong><?=mlv_h(mlv_date($r->start_date));?></strong><br><small>s/d <?=mlv_h(mlv_date($r->end_date));?></small><br><span class="ml-chip"><?=mlv_h($r->start_half_day.' / '.$r->end_half_day);?></span></td><td><strong><?=mlv_num($r->total_days,2);?> hari</strong><br><small>Quota <?=mlv_num($r->leave_quota_before,2);?> -> <?=mlv_num($r->leave_quota_after,2);?></small></td><td><?=mlv_h($r->handover_no?($r->handover_no.' - '.$r->handover_name):'-');?></td><td><?=mlv_h($r->approver_no?($r->approver_no.' - '.$r->approver_name):'-');?><br><small>HR: <?=mlv_h($r->hr_no?($r->hr_no.' - '.$r->hr_name):'-');?></small></td><td><span class="label label-<?=mlv_status_class($r->workflow_status);?>"><?=mlv_h($r->workflow_status);?></span><br><small><?=mlv_h($r->decision);?></small></td><td><?php $logs=isset($approvalMap[$r->id])?$approvalMap[$r->id]:array(); if(!$logs): ?><span class="text-muted">Belum ada approval log.</span><?php else: ?><ul class="ml-timeline"><?php foreach($logs as $l): ?><li><b><?=mlv_h($l->approval_step);?></b> <?=mlv_h($l->decision);?> <small><?=mlv_h($l->decision_date?:'-');?></small><br><small><?=mlv_h(trim(($l->employee_no?:'').' '.($l->full_name?:''))?:'-');?></small></li><?php endforeach; ?></ul><?php endif; ?></td><td><button type="button" class="btn btn-info btn-xs btn-my-leave-detail" data-no="<?=mlv_h($r->leave_no);?>" data-type="<?=mlv_h($r->leave_type);?>" data-period="<?=mlv_h(mlv_date($r->start_date).' s/d '.mlv_date($r->end_date));?>" data-days="<?=mlv_num($r->total_days,2);?> hari" data-status="<?=mlv_h($r->workflow_status);?>" data-reason="<?=mlv_h($r->reason);?>" data-approver="<?=mlv_h($r->approver_no?($r->approver_no.' - '.$r->approver_name):'-');?>"><i class="fa fa-eye"></i></button> <?php if(in_array($r->workflow_status,array('DRAFT','RETURNED'),true)): ?><button class="btn btn-primary btn-xs btn-edit-leave" data-id="<?=mlv_h($r->id);?>"><i class="fa fa-pencil"></i></button><?php endif; ?> <?php if(!in_array($r->workflow_status,array('APPROVED','REJECTED','CANCELLED'),true)): ?><button class="btn btn-warning btn-xs btn-cancel-leave" data-id="<?=mlv_h($r->id);?>" data-no="<?=mlv_h($r->leave_no);?>"><i class="fa fa-ban"></i></button><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div></div>

