="col-md-2 form-group"><label class="required-label"><?=hr_h('hr_end_date', 'End Date');?></label><input name="end_date" id="ml_end_date" class="form-control ml-date" value="<?=date('Y-m-d');?>"></div><div class="col-md-2 form-group"><label>Start Half</label><select name="start_half_day" id="ml_start_half_day" class="form-control ml-select2-modal"><option>FULL_DAY</option><option>AM</option><option>PM</option></select></div><div class="col-md-2 form-group"><label>End Half</label><select name="end_half_day" id="ml_end_half_day" class="form-control ml-select2-modal"><option>FULL_DAY</option><option>AM</option><option>PM</option></select></div><div class="col-md-1 form-group"><label>Days</label><input id="ml_total_days" class="form-control" readonly></div></div><div class="row"><div class="col-md-2 form-group"><label>Quota Before</label><input name="leave_quota_before" id="ml_leave_quota_before" type="number" step="0.01" class="form-control" value="12"></div><div class="col-md-2 form-group"><label>Quota After</label><input id="ml_leave_quota_after" class="form-control" readonly></div><div class="col-md-4 form-group"><label>Handover To</label><select name="handover_to_employee_id" id="ml_handover_to_employee_id" class="form-control"></select></div><div class="col-md-4 form-group"><label>Attachment Ref</label><input name="attachment_ref" id="ml_attachment_ref" class="form-control" placeholder="Opsional, misal nomor surat dokter"></div></div><div class="form-group"><label class="required-label">Reason</label><textarea name="reason" id="ml_reason" class="form-control" rows="3" placeholder="Jelaskan alasan cuti/izin secara singkat"></textarea></div><div class="form-group"><label><?=hr_h('common_remarks', 'Remarks');?></label><textarea name="remarks" id="ml_remarks" class="form-control" rows="2"></textarea></div><div class="alert alert-danger" id="ml_form_error" style="display:none"></div></div><div class="modal-footer"><button type="button" class="btn btn-default" data-dismiss="modal">Batal</button><button type="button" class="btn btn-info btn-save-leave" data-status="DRAFT"><i class="fa fa-save"></i> Save Draft</button><button type="button" class="btn btn-primary btn-save-leave" data-status="SUBMITTED"><i class="fa fa-send"></i> Submit Request</button></div></form></div></div></div>
