<script>
function mlCalcDays(){var a=new Date($('#ml_start_date').val()),b=new Date($('#ml_end_date').val()),d=1;if(!isNaN(a)&&!isNaN(b)&&b>=a)d=((b-a)/86400000)+1;if($('#ml_start_half_day').val()==='PM')d-=.5;if($('#ml_end_half_day').val()==='AM')d-=.5;d=Math.max(.5,d);var q=parseFloat($('#ml_leave_quota_before').val()||0),type=$('#ml_leave_type').val(),deduct=['ANNUAL_LEAVE','SPECIAL_LEAVE','PERMISSION'].indexOf(type)>=0?d:0;$('#ml_total_days').val(d.toFixed(2));$('#ml_leave_quota_after').val(Math.max(0,q-deduct).toFixed(2))}
function mlReset(){var f=$('#formMyLeave')[0];f.reset();$('#ml_id').val('');$('#ml_submit_status').val('DRAFT');$('#ml_handover_to_employee_id').val(null).trigger('change');$('#ml_leave_type').val('ANNUAL_LEAVE').trigger('change');$('#ml_start_half_day,#ml_end_half_day').val('FULL_DAY').trigger('change');$('#ml_request_date,#ml_start_date,#ml_end_date').val('<?=date('Y-m-d');?>');$('#ml_leave_quota_before').val('12');$('#ml_form_error').hide().text('');mlCalcDays();$('#modal_my_leave .modal-title').html('<i class="fa fa-calendar-plus-o"></i> Create Leave')}
function mlShowDetail(b){$('#my_leave_detail_body').html('<div class="table-responsive"><table class="table table-bordered table-striped"><tr><th style="width:170px">Leave No</th><td>'+b.data('no')+'</td></tr><tr><th>Type</th><td>'+b.data('type')+'</td></tr><tr><th><?=hr_h('hr_period', 'Period');?></th><td>'+b.data('period')+'</td></tr><tr><th>Total Days</th><td>'+b.data('days')+'</td></tr><tr><th><?=hr_h('common_status', 'Status');?></th><td>'+b.data('status')+'</td></tr><tr><th>Approver</th><td>'+b.data('approver')+'</td></tr><tr><th>Reason</th><td>'+b.data('reason')+'</td></tr></table></div>');$('#modal_my_leave_detail').modal('show')}
function mlSetSelect(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change')}
$(function(){if($.fn.datepicker)$('.ml-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});if($.fn.select2){$('.ml-select2').select2({width:'100%',allowClear:true});$('.ml-select2-modal').select2({width:'100%',dropdownParent:$('#modal_my_leave')});$('#ml_handover_to_employee_id').select2({width:'100%',allowClear:true,placeholder:'Pilih pengganti/handover',dropdownParent:$('#modal_my_leave'),ajax:{url:'<?=base_admin();?>modul/my_leave/my_leave_action.php?act=handover_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''}},processResults:function(d){return{results:d.results||[]}}}})}if($.fn.DataTable)$('#dtb_my_leave').DataTable({pageLength:25,order:[[0,'desc']],columnDefs:[{targets:[6,7],orderable:false}]});$('#btnAddMyLeave').click(function(){mlReset();$('#modal_my_leave').modal({backdrop:'static',keyboard:false})});$('#btnExportMyLeave').click(function(){window.location='<?=base_admin();?>modul/my_leave/my_leave_action.php?act=export&'+$('#formFilterMyLeave').serialize()});$(document).on('click','.btn-my-leave-detail',function(){mlShowDetail($(this));});$('#ml_start_date,#ml_end_date,#ml_start_half_day,#ml_end_half_day,#ml_leave_quota_before,#ml_leave_type').on('change keyup',mlCalcDays);$('.btn-save-leave').click(function(){var b=$(this),status=b.data('status');$('#ml_submit_status').val(status);$('#ml_form_error').hide().text('');b.prop('disabled',true);$.post('<?=base_admin();?>modul/my_leave/my_leave_action.php?act=save',$('#formMyLeave').serialize(),function(r){b.prop('disabled',false);if(r.status==='good'){$('#modal_my_leave').modal('hide');Swal.fire('Saved',r.message,'success').then(function(){location.reload()})}else $('#ml_form_error').text(r.error_message||'Gagal menyimpan.').show()},'json').fail(function(x){b.prop('disabled',false);$('#ml_form_error').text(x.responseText||'Gagal menyimpan.').show()})});$(document).on('click','.btn-edit-leave',function(){mlReset();$.post('<?=base_admin();?>modul/my_leave/my_leave_action.php?act=get',{id:$(this).data('id')},function(r){if(r.status!=='good'){Swal.fire('Error',r.error_message,'error');return}var h=r.data;$('#ml_id').val(h.id);$('#ml_request_date').val(h.request_date);$('#ml_leave_type').val(h.leave_type).trigger('change');$('#ml_start_date').val(h.start_date);$('#ml_end_date').val(h.end_date);$('#ml_start_half_day').val(h.start_half_day).trigger('change');$('#ml_end_half_day').val(h.end_half_day).trigger('change');$('#ml_leave_quota_before').val(h.leave_quota_before);$('#ml_attachment_ref').val(h.attachment_ref);$('#ml_reason').val(h.reason);$('#ml_remarks').val(h.remarks);mlSetSelect('#ml_handover_to_employee_id',h.handover_to_employee_id,h.handover_text);mlCalcDays();$('#modal_my_leave .modal-title').html('<i class="fa fa-pencil"></i> Edit Leave '+h.leave_no);$('#modal_my_leave').modal({backdrop:'static',keyboard:false})},'json')});$(document).on('click','.btn-cancel-leave',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:'Cancel leave request?',text:no,input:'textarea',inputPlaceholder:'Alasan pembatalan',showCancelButton:true,confirmButtonText:'Cancel Request'}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/my_leave/my_leave_action.php?act=cancel',{id:id,reason:x.value||''},function(r){if(r.status==='good')Swal.fire('Cancelled',r.message,'success').then(function(){location.reload()});else Swal.fire('Error',r.error_message,'error')},'json')})});Highcharts.setOptions({lang:{thousandsSep:','},colors:['#0f766e','#2563eb','#f59e0b','#dc2626','#7c3aed','#0891b2','#16a34a','#64748b']});Highcharts.chart('ml_type_chart',{chart:{type:'pie'},title:{text:null},tooltip:{pointFormat:'<b>{point.y}</b> request'},plotOptions:{pie:{innerSize:'58%',dataLabels:{enabled:true,format:'{point.name}: {point.y}'}}},series:[{name:'Type',data:<?=json_encode($typeChart);?>}],credits:{enabled:false}});Highcharts.chart('ml_status_chart',{chart:{type:'bar'},title:{text:null},xAxis:{type:'category'},yAxis:{title:{text:'Request'},allowDecimals:false},legend:{enabled:false},series:[{name:'Status',data:<?=json_encode($statusChart);?>}],credits:{enabled:false}})});
</script>
